{
  "name": "Vani - India News Voicebot",
  "description": "An intelligent voicebot powered by Gemini 3 Flash that delivers personalized, India-specific news briefings with real-time search grounding.",
  "requestFramePermissions": [
    "microphone"
  ]
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface NewsSource {
  title: string;
  uri: string;
}

export interface NewsItem {
  headline: string;
  summary: string;
  sources: NewsSource[];
}

export enum Interest {
  POLITICS = 'Politics',
  CRICKET = 'Cricket',
  BOLLYWOOD = 'Bollywood',
  TECHNOLOGY = 'Technology',
  BUSINESS = 'Business',
  STARTUPS = 'Startups',
  TRAVEL = 'Travel',
}

export enum AppState {
  IDLE = 'IDLE',
  LISTENING = 'LISTENING',
  PROCESSING = 'PROCESSING',
  SPEAKING = 'SPEAKING',
}

export interface ChatMessage {
  role: 'user' | 'assistant';
  text: string;
  sources?: NewsSource[];
  timestamp: number;
}

// Utility to decode raw PCM data from Gemini TTS
export function base64ToUint8Array(base64: string): Uint8Array {
  const binaryString = atob(base64);
  const len = binaryString.length;
  const bytes = new Uint8Array(len);
  for (let i = 0; i < len; i++) {
    bytes[i] = binaryString.charCodeAt(i);
  }
  return bytes;
}

export async function decodeAudioData(
  data: Uint8Array,
  ctx: AudioContext,
  sampleRate: number = 24000,
  numChannels: number = 1
): Promise<AudioBuffer> {
  const dataInt16 = new Int16Array(data.buffer);
  const frameCount = dataInt16.length / numChannels;
  const buffer = ctx.createBuffer(numChannels, frameCount, sampleRate);

  for (let channel = 0; channel < numChannels; channel++) {
    const channelData = buffer.getChannelData(channel);
    for (let i = 0; i < frameCount; i++) {
      // Convert Int16 to Float32 [-1.0, 1.0]
      channelData[i] = dataInt16[i * numChannels + channel] / 32768.0;
    }
  }
  return buffer;
}

export function blobToBase64(blob: Blob): Promise<string> {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.onloadend = () => {
      const result = reader.result as string;
      const base64 = result.split(',')[1];
      resolve(base64);
    };
    reader.onerror = reject;
    reader.readAsDataURL(blob);
  });
}

import { GoogleGenAI, Modality } from "@google/genai";
import { blobToBase64 } from "./audioUtils";
import { Interest } from "../types";

// Initialize Gemini Client
const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const generateNewsResponse = async (
  audioBlob: Blob | null,
  textInput: string | null,
  interests: Interest[]
) => {
  const interestString = interests.length > 0 ? interests.join(", ") : "General India News";

  const systemInstruction = `You are Vani, a professional, friendly, and concise Indian news anchor. 
  Your goal is to provide the latest India-specific news based on the user's request and their selected interests: [${interestString}].

  1. If the user provides audio/text, answer their specific query using Google Search.
  2. If the user just says "Start" or generic greeting, give a briefing on top stories matching their interests.
  3. ALWAYS use Google Search to get real-time facts.
  4. Keep the response spoken-word friendly (avoid complex lists, use natural transitions).
  5. Keep it under 150 words unless asked for more details.
  `;

  const parts: any[] = [];

  if (audioBlob) {
    const base64Audio = await blobToBase64(audioBlob);
    parts.push({
      inlineData: {
        mimeType: audioBlob.type || 'audio/webm',
        data: base64Audio
      }
    });
  }

  if (textInput) {
    parts.push({ text: textInput });
  }

  if (parts.length === 0) {
    parts.push({ text: "Give me my news briefing." });
  }

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: {
        parts: parts,
      },
      config: {
        systemInstruction: systemInstruction,
        tools: [{ googleSearch: {} }],
        thinkingConfig: { thinkingBudget: 0 } // Low latency preferred for voicebot
      }
    });

    const text = response.text;
    const chunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks || [];

    // Extract sources
    const sources = chunks
      .map((chunk: any) => chunk.web)
      .filter((web: any) => web && web.uri && web.title)
      .map((web: any) => ({ title: web.title, uri: web.uri }));

    // Remove duplicates based on URI
    const uniqueSources = Array.from(new Map(sources.map((s:any) => [s.uri, s])).values());

    return { text, sources: uniqueSources as {title: string, uri: string}[] };

  } catch (error) {
    console.error("News Generation Error:", error);
    throw error;
  }
};

export const generateSpeech = async (text: string): Promise<string> => {
  try {
    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash-preview-tts",
      contents: [{ parts: [{ text: text }] }],
      config: {
        responseModalities: [Modality.AUDIO],
        speechConfig: {
          voiceConfig: {
            prebuiltVoiceConfig: { voiceName: 'Kore' }, // Kore has a nice neutral tone
          },
        },
      },
    });

    const base64Audio = response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;
    if (!base64Audio) throw new Error("No audio data returned");

    return base64Audio;
  } catch (error) {
    console.error("TTS Generation Error:", error);
    throw error;
  }
};

import React, { useEffect, useRef } from 'react';

interface VisualizerProps {
  isActive: boolean;
  mode: 'listening' | 'speaking' | 'idle';
}

const Visualizer: React.FC<VisualizerProps> = ({ isActive, mode }) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const animationRef = useRef<number>();

  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    let time = 0;
    const width = canvas.width;
    const height = canvas.height;

    const animate = () => {
      ctx.clearRect(0, 0, width, height);

      if (isActive) {
        time += 0.05;

        const color = mode === 'listening' ? '#ef4444' : '#6366f1'; // Red for listening, Indigo for speaking
        ctx.strokeStyle = color;
        ctx.lineWidth = 2;
        ctx.lineCap = 'round';

        const centerY = height / 2;

        ctx.beginPath();
        for (let x = 0; x < width; x++) {
          // Create a wave effect
          const frequency = mode === 'listening' ? 0.05 : 0.03;
          const amplitude = mode === 'listening' 
            ? Math.sin(time * 2) * 15 + 20 
            : Math.sin(time * 3) * 10 + 15;

          const y = centerY + Math.sin(x * frequency + time) * 
                   Math.cos(x * 0.02 + time) * amplitude;

          if (x === 0) ctx.moveTo(x, y);
          else ctx.lineTo(x, y);
        }
        ctx.stroke();
      } else {
        // Idle line
        ctx.strokeStyle = '#334155';
        ctx.lineWidth = 1;
        ctx.beginPath();
        ctx.moveTo(0, height / 2);
        ctx.lineTo(width, height / 2);
        ctx.stroke();
      }

      animationRef.current = requestAnimationFrame(animate);
    };

    animate();

    return () => {
      if (animationRef.current) cancelAnimationFrame(animationRef.current);
    };
  }, [isActive, mode]);

  return (
    <canvas 
      ref={canvasRef} 
      width={300} 
      height={80} 
      className="w-full h-20 rounded-lg bg-slate-900/50 backdrop-blur-sm"
    />
  );
};

export default Visualizer;

import React from 'react';
import { ChatMessage, NewsSource } from '../types';

interface NewsCardProps {
  message: ChatMessage;
}

const NewsCard: React.FC<NewsCardProps> = ({ message }) => {
  const isUser = message.role === 'user';

  return (
    <div className={`flex w-full mb-6 ${isUser ? 'justify-end' : 'justify-start'}`}>
      <div 
        className={`max-w-[85%] rounded-2xl p-5 ${
          isUser 
            ? 'bg-indigo-600 text-white rounded-br-none' 
            : 'bg-slate-800 border border-slate-700 text-slate-100 rounded-bl-none shadow-xl'
        }`}
      >
        <p className="text-sm md:text-base leading-relaxed whitespace-pre-wrap font-light">
          {message.text}
        </p>

        {!isUser && message.sources && message.sources.length > 0 && (
          <div className="mt-4 pt-4 border-t border-slate-700">
            <p className="text-xs font-semibold text-slate-400 mb-2 uppercase tracking-wider">Sources</p>
            <div className="flex flex-wrap gap-2">
              {message.sources.map((source, idx) => (
                <a
                  key={idx}
                  href={source.uri}
                  target="_blank"
                  rel="noopener noreferrer"
                  className="inline-flex items-center px-2 py-1 bg-slate-900 hover:bg-slate-950 text-slate-300 text-xs rounded transition-colors truncate max-w-full"
                  title={source.title}
                >
                  <span className="truncate max-w-[150px]">{source.title}</span>
                  <svg className="w-3 h-3 ml-1 flex-shrink-0" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M10 6H6a2 2 0 00-2 2v10a2 2 0 002 2h10a2 2 0 002-2v-4M14 4h6m0 0v6m0-6L10 14" />
                  </svg>
                </a>
              ))}
            </div>
          </div>
        )}
      </div>
    </div>
  );
};

export default NewsCard;

import React, { useState, useRef, useEffect, useCallback } from 'react';
import { Interest, AppState, ChatMessage } from './types';
import { generateNewsResponse, generateSpeech } from './services/geminiService';
import { base64ToUint8Array, decodeAudioData } from './services/audioUtils';
import Visualizer from './components/Visualizer';
import NewsCard from './components/NewsCard';

const INTERESTS_LIST = Object.values(Interest);

const App: React.FC = () => {
  // State
  const [selectedInterests, setSelectedInterests] = useState<Interest[]>([]);
  const [appState, setAppState] = useState<AppState>(AppState.IDLE);
  const [chatHistory, setChatHistory] = useState<ChatMessage[]>([]);
  const [errorMsg, setErrorMsg] = useState<string | null>(null);

  // Refs
  const mediaRecorderRef = useRef<MediaRecorder | null>(null);
  const audioChunksRef = useRef<Blob[]>([]);
  const audioContextRef = useRef<AudioContext | null>(null);
  const sourceNodeRef = useRef<AudioBufferSourceNode | null>(null);
  const chatEndRef = useRef<HTMLDivElement>(null);

  // Initialize AudioContext
  useEffect(() => {
    audioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({
      sampleRate: 24000, 
    });
    return () => {
      audioContextRef.current?.close();
    };
  }, []);

  // Scroll to bottom on new message
  useEffect(() => {
    chatEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [chatHistory, appState]);

  const toggleInterest = (interest: Interest) => {
    setSelectedInterests((prev) =>
      prev.includes(interest)
        ? prev.filter((i) => i !== interest)
        : [...prev, interest]
    );
  };

  const stopAudioPlayback = () => {
    if (sourceNodeRef.current) {
      sourceNodeRef.current.stop();
      sourceNodeRef.current = null;
    }
  };

  const playAudioResponse = async (base64Audio: string) => {
    if (!audioContextRef.current) return;

    // Stop any current playback
    stopAudioPlayback();

    // Resume context if suspended (browser policy)
    if (audioContextRef.current.state === 'suspended') {
      await audioContextRef.current.resume();
    }

    try {
      const audioBytes = base64ToUint8Array(base64Audio);
      const audioBuffer = await decodeAudioData(audioBytes, audioContextRef.current);

      const source = audioContextRef.current.createBufferSource();
      source.buffer = audioBuffer;
      source.connect(audioContextRef.current.destination);

      sourceNodeRef.current = source;

      setAppState(AppState.SPEAKING);
      source.start(0);

      source.onended = () => {
        setAppState(AppState.IDLE);
        sourceNodeRef.current = null;
      };
    } catch (err) {
      console.error("Audio Playback Error", err);
      setAppState(AppState.IDLE);
    }
  };

  const handleNewsQuery = async (audioBlob: Blob | null, text: string | null = null) => {
    setAppState(AppState.PROCESSING);
    setErrorMsg(null);

    // Add user message to UI immediately for feedback
    const userMsg: ChatMessage = {
      role: 'user',
      text: audioBlob ? "Listening to your request..." : (text || "Start Briefing"),
      timestamp: Date.now()
    };

    if (text) {
        setChatHistory(prev => [...prev, userMsg]);
    }

    try {
      // 1. Get News Content
      const newsData = await generateNewsResponse(audioBlob, text, selectedInterests);

      if (!newsData || !newsData.text) throw new Error("No news generated");

      // Update user message if it was audio
      if (audioBlob) {
        setChatHistory(prev => [...prev, { ...userMsg, text: "🎤 Audio Query" }]);
      }

      const botMsg: ChatMessage = {
        role: 'assistant',
        text: newsData.text,
        sources: newsData.sources,
        timestamp: Date.now()
      };
      setChatHistory(prev => [...prev, botMsg]);

      // 2. Get Audio Speech
      const speechBase64 = await generateSpeech(newsData.text);

      // 3. Play Audio
      await playAudioResponse(speechBase64);

    } catch (err: any) {
      console.error(err);
      setErrorMsg("Failed to get the latest news. Please try again.");
      setAppState(AppState.IDLE);
    }
  };

  const startRecording = async () => {
    stopAudioPlayback();
    setErrorMsg(null);

    try {
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      const recorder = new MediaRecorder(stream);
      mediaRecorderRef.current = recorder;
      audioChunksRef.current = [];

      recorder.ondataavailable = (e) => {
        if (e.data.size > 0) audioChunksRef.current.push(e.data);
      };

      recorder.onstop = async () => {
        const audioBlob = new Blob(audioChunksRef.current, { type: 'audio/webm' });
        await handleNewsQuery(audioBlob);

        // Stop all tracks
        stream.getTracks().forEach(track => track.stop());
      };

      recorder.start();
      setAppState(AppState.LISTENING);
    } catch (err) {
      console.error("Microphone Error", err);
      setErrorMsg("Microphone access denied or not available.");
    }
  };

  const stopRecording = () => {
    if (mediaRecorderRef.current && mediaRecorderRef.current.state === 'recording') {
      mediaRecorderRef.current.stop();
      // State transition handled in onstop
    }
  };

  const handleMicClick = () => {
    if (appState === AppState.LISTENING) {
      stopRecording();
    } else if (appState === AppState.SPEAKING) {
        stopAudioPlayback();
        setAppState(AppState.IDLE);
    } else if (appState === AppState.IDLE) {
      startRecording();
    }
  };

  return (
    <div className="min-h-screen bg-slate-900 text-slate-100 flex flex-col items-center relative overflow-hidden">

      {/* Background Ambience */}
      <div className="absolute top-0 left-0 w-full h-full overflow-hidden pointer-events-none z-0">
        <div className="absolute -top-[20%] -right-[20%] w-[600px] h-[600px] bg-indigo-900/20 rounded-full blur-[100px]" />
        <div className="absolute top-[40%] -left-[20%] w-[500px] h-[500px] bg-rose-900/20 rounded-full blur-[100px]" />
      </div>

      <div className="relative z-10 w-full max-w-2xl px-4 py-6 flex flex-col h-screen">

        {/* Header */}
        <header className="flex items-center justify-between mb-6">
          <div className="flex items-center space-x-3">
            <div className="w-10 h-10 bg-gradient-to-br from-indigo-500 to-rose-500 rounded-xl flex items-center justify-center shadow-lg shadow-indigo-500/20">
               <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6 text-white" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                 <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 20H5a2 2 0 01-2-2V6a2 2 0 012-2h10a2 2 0 012 2v1m2 13a2 2 0 01-2-2V7m2 13a2 2 0 002-2V9a2 2 0 00-2-2h-2m-4-3H9M7 16h6M7 8h6v4H7V8z" />
               </svg>
            </div>
            <div>
              <h1 className="text-xl font-bold tracking-tight">Vani News</h1>
              <p className="text-xs text-slate-400">Powered by Gemini 3 Flash</p>
            </div>
          </div>

          <div className="flex items-center space-x-2">
            <span className={`w-2 h-2 rounded-full ${appState === AppState.IDLE ? 'bg-slate-500' : 'bg-green-500 animate-pulse'}`} />
            <span className="text-xs font-medium text-slate-400 uppercase">{appState}</span>
          </div>
        </header>

        {/* Categories */}
        <div className="mb-6">
          <p className="text-xs font-semibold text-slate-500 mb-3 uppercase tracking-wider">Customize Your Feed</p>
          <div className="flex flex-wrap gap-2">
            {INTERESTS_LIST.map((interest) => (
              <button
                key={interest}
                onClick={() => toggleInterest(interest)}
                className={`px-3 py-1.5 rounded-full text-xs font-medium transition-all duration-200 border ${
                  selectedInterests.includes(interest)
                    ? 'bg-indigo-600 border-indigo-500 text-white shadow-lg shadow-indigo-900/50'
                    : 'bg-slate-800/50 border-slate-700 text-slate-400 hover:bg-slate-800 hover:text-slate-200'
                }`}
              >
                {interest}
              </button>
            ))}
          </div>
        </div>

        {/* Chat Area */}
        <div className="flex-1 overflow-y-auto scrollbar-hide -mx-4 px-4 pb-4">
            {chatHistory.length === 0 && (
                <div className="h-full flex flex-col items-center justify-center text-center opacity-50">
                    <p className="text-slate-500 mb-2">Tap the microphone to start</p>
                    <p className="text-sm text-slate-600">"Tell me the latest cricket score"</p>
                    <p className="text-sm text-slate-600">"What's happening in Bangalore?"</p>
                </div>
            )}
            {chatHistory.map((msg, idx) => (
                <NewsCard key={idx} message={msg} />
            ))}
            {appState === AppState.PROCESSING && (
                 <div className="flex justify-start mb-6">
                     <div className="bg-slate-800 border border-slate-700 rounded-2xl rounded-bl-none p-4 flex items-center space-x-2">
                         <div className="w-2 h-2 bg-indigo-400 rounded-full animate-bounce" style={{ animationDelay: '0ms' }} />
                         <div className="w-2 h-2 bg-indigo-400 rounded-full animate-bounce" style={{ animationDelay: '150ms' }} />
                         <div className="w-2 h-2 bg-indigo-400 rounded-full animate-bounce" style={{ animationDelay: '300ms' }} />
                     </div>
                 </div>
            )}
            <div ref={chatEndRef} />
        </div>

        {/* Error Message */}
        {errorMsg && (
            <div className="absolute bottom-24 left-0 w-full px-4">
                <div className="bg-red-500/10 border border-red-500/50 text-red-400 px-4 py-2 rounded-lg text-sm text-center">
                    {errorMsg}
                </div>
            </div>
        )}

        {/* Bottom Controls */}
        <div className="mt-4 pt-4 border-t border-slate-800/50 bg-slate-900/80 backdrop-blur-md sticky bottom-0">
          <Visualizer isActive={appState !== AppState.IDLE && appState !== AppState.PROCESSING} mode={appState === AppState.LISTENING ? 'listening' : 'speaking'} />

          <div className="flex items-center justify-center mt-6 mb-2 space-x-6">
            <button 
                onClick={() => handleNewsQuery(null, "Give me a summary")}
                className="p-3 rounded-full bg-slate-800 text-slate-400 hover:bg-slate-700 hover:text-white transition-colors"
                disabled={appState !== AppState.IDLE}
            >
                <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" viewBox="0 0 20 20" fill="currentColor">
                    <path fillRule="evenodd" d="M10 18a8 8 0 100-16 8 8 0 000 16zm1-11a1 1 0 10-2 0v2H7a1 1 0 100 2h2v2a1 1 0 102 0v-2h2a1 1 0 100-2h-2V7z" clipRule="evenodd" />
                </svg>
            </button>

            <button
              onClick={handleMicClick}
              disabled={appState === AppState.PROCESSING}
              className={`w-16 h-16 rounded-full flex items-center justify-center shadow-2xl transition-all duration-300 transform hover:scale-105 ${
                appState === AppState.LISTENING
                  ? 'bg-red-500 shadow-red-500/40 animate-pulse'
                  : appState === AppState.SPEAKING
                    ? 'bg-indigo-500 shadow-indigo-500/40'
                    : 'bg-white text-slate-900 shadow-white/20'
              }`}
            >
              {appState === AppState.LISTENING ? (
                 <svg xmlns="http://www.w3.org/2000/svg" className="h-8 w-8 text-white" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M21 12a9 9 0 11-18 0 9 9 0 0118 0z" />
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 10a1 1 0 011-1h4a1 1 0 011 1v4a1 1 0 01-1 1h-4a1 1 0 01-1-1v-4z" />
                </svg>
              ) : appState === AppState.SPEAKING ? (
                 <svg xmlns="http://www.w3.org/2000/svg" className="h-8 w-8 text-white" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                     <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M21 12a9 9 0 11-18 0 9 9 0 0118 0z" />
                     <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 10a1 1 0 011-1h4a1 1 0 011 1v4a1 1 0 01-1 1h-4a1 1 0 01-1-1v-4z" />
                </svg>
              ) : (
                <svg xmlns="http://www.w3.org/2000/svg" className="h-8 w-8" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 11a7 7 0 01-7 7m0 0a7 7 0 01-7-7m7 7v4m0 0H8m4 0h4m-4-8a3 3 0 01-3-3V5a3 3 0 116 0v6a3 3 0 01-3 3z" />
                </svg>
              )}
            </button>

            <div className="w-11 h-11" /> {/* Spacer for symmetry */}
          </div>
          <p className="text-center text-[10px] text-slate-500 pb-2">
            {appState === AppState.LISTENING ? 'Listening...' : appState === AppState.SPEAKING ? 'Speaking...' : appState === AppState.PROCESSING ? 'Thinking...' : 'Tap to speak'}
          </p>
        </div>
      </div>
    </div>
  );
};

export default App;

{
  "name": "Vani - India News Voicebot",
  "description": "An intelligent voicebot powered by Gemini Live API that delivers personalized, India-specific news briefings with real-time interruption handling.",
  "requestFramePermissions": [
    "microphone"
  ]
}

export interface NewsSource {
  title: string;
  uri: string;
}

export enum Interest {
  POLITICS = 'Politics',
  CRICKET = 'Cricket',
  BOLLYWOOD = 'Bollywood',
  TECHNOLOGY = 'Technology',
  BUSINESS = 'Business',
  STARTUPS = 'Startups',
  TRAVEL = 'Travel',
}

export enum AppState {
  DISCONNECTED = 'DISCONNECTED',
  CONNECTING = 'CONNECTING',
  CONNECTED = 'CONNECTED',
  ERROR = 'ERROR'
}

export interface ChatMessage {
  role: 'user' | 'assistant';
  text: string;
  isFinal: boolean;
  timestamp: number;
}

// Utility to decode raw PCM data
export function base64ToUint8Array(base64: string): Uint8Array {
  const binaryString = atob(base64);
  const len = binaryString.length;
  const bytes = new Uint8Array(len);
  for (let i = 0; i < len; i++) {
    bytes[i] = binaryString.charCodeAt(i);
  }
  return bytes;
}

export async function decodeAudioData(
  data: Uint8Array,
  ctx: AudioContext,
  sampleRate: number = 24000,
  numChannels: number = 1
): Promise<AudioBuffer> {
  const dataInt16 = new Int16Array(data.buffer);
  const frameCount = dataInt16.length / numChannels;
  const buffer = ctx.createBuffer(numChannels, frameCount, sampleRate);

  for (let channel = 0; channel < numChannels; channel++) {
    const channelData = buffer.getChannelData(channel);
    for (let i = 0; i < frameCount; i++) {
      // Convert Int16 to Float32 [-1.0, 1.0]
      channelData[i] = dataInt16[i * numChannels + channel] / 32768.0;
    }
  }
  return buffer;
}

// Convert Float32Array (Web Audio API) to Base64 encoded Int16 PCM (Gemini API)
export function float32ToBase64PCM(float32: Float32Array): string {
  const l = float32.length;
  const int16 = new Int16Array(l);
  for (let i = 0; i < l; i++) {
    // Clamp values to [-1, 1] before converting to Int16
    const s = Math.max(-1, Math.min(1, float32[i]));
    int16[i] = s < 0 ? s * 0x8000 : s * 0x7FFF;
  }

  let binary = '';
  const bytes = new Uint8Array(int16.buffer);
  const len = bytes.byteLength;
  for (let i = 0; i < len; i++) {
    binary += String.fromCharCode(bytes[i]);
  }
  return btoa(binary);
}

import { GoogleGenAI, Modality, LiveServerMessage } from "@google/genai";
import { Interest } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export class LiveNewsSession {
  private session: any = null;
  private currentInterestString: string = "";

  constructor() {}

  async connect(
    interests: Interest[],
    onOpen: () => void,
    onMessage: (message: LiveServerMessage) => void,
    onClose: (event: CloseEvent) => void,
    onError: (error: ErrorEvent) => void
  ) {
    this.currentInterestString = interests.length > 0 ? interests.join(", ") : "General India News";
    const today = new Date().toLocaleDateString('en-IN', { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' });

    const systemInstruction = `You are Vani, a professional Indian news anchor.
    Today is ${today}.
    User Interests: [${this.currentInterestString}].

    Your Mission:
    1. IMMERSE yourself as a news anchor.
    2. IMMEDIATELY upon connection, welcome the user and start a briefing of the top headlines for today based on their interests. Do not wait for the user to say "Start".
    3. Use the "Google Search" tool to ensure all news is accurate and up-to-the-minute for today.
    4. Be concise, engaging, and clear.
    5. Allow the user to interrupt with questions.
    6. If the user asks a cross-question, answer it briefly and return to the news flow if appropriate.
    7. RESTRICTIONS:
       - ONLY answer questions about news, current events, or India.
       - Do NOT provide explicit, gory, or sexually explicit details.
       - If the user is abusive or uses foul language, strictly say "I am terminating this session due to abusive behavior" and stop responding.
    `;

    this.session = await ai.live.connect({
      model: 'gemini-2.5-flash-native-audio-preview-12-2025',
      callbacks: {
        onopen: onOpen,
        onmessage: onMessage,
        onclose: onClose,
        onerror: onError,
      },
      config: {
        responseModalities: [Modality.AUDIO],
        tools: [{ googleSearch: {} }],
        systemInstruction: systemInstruction,
        speechConfig: {
          voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Kore' } }
        },
        inputAudioTranscription: { model: "gemini-2.5-flash-native-audio-preview-12-2025" },
        outputAudioTranscription: { model: "gemini-2.5-flash-native-audio-preview-12-2025" }
      }
    });

    return this.session;
  }

  async sendAudioChunk(base64PCM: string) {
    if (this.session) {
      this.session.sendRealtimeInput({
        media: {
          mimeType: 'audio/pcm;rate=16000',
          data: base64PCM
        }
      });
    }
  }

  async close() {
    if (this.session) {
      // There isn't a direct close method exposed on the session object in the current type definition wrapper
      // usually, but we can close the underlying socket if accessible, or just let the caller handle cleanup.
      // The provided example uses session.close() in the comments rules but not in the code block.
      // We will assume the session object might have it or we just stop sending data.
      // Checking the 'Live' guidelines again: "Use session.close() to close the connection".
      try {
        (this.session as any).close(); 
      } catch (e) {
        console.warn("Error closing session", e);
      }
      this.session = null;
    }
  }
}

import React, { useState, useRef, useEffect } from 'react';
import { Interest, AppState, ChatMessage } from './types';
import { LiveNewsSession } from './services/geminiService';
import { decodeAudioData, float32ToBase64PCM } from './services/audioUtils';
import Visualizer from './components/Visualizer';

const INTERESTS_LIST = Object.values(Interest);

const App: React.FC = () => {
  // UI State
  const [selectedInterests, setSelectedInterests] = useState<Interest[]>([]);
  const [appState, setAppState] = useState<AppState>(AppState.DISCONNECTED);
  const [chatHistory, setChatHistory] = useState<ChatMessage[]>([]);
  const [errorMsg, setErrorMsg] = useState<string | null>(null);
  const [volume, setVolume] = useState<number>(0); // For visualizer

  // Audio Context Refs
  const audioContextRef = useRef<AudioContext | null>(null);
  const inputContextRef = useRef<AudioContext | null>(null);
  const nextStartTimeRef = useRef<number>(0);
  const audioSourcesRef = useRef<Set<AudioBufferSourceNode>>(new Set());
  const processorRef = useRef<ScriptProcessorNode | null>(null);
  const inputStreamRef = useRef<MediaStream | null>(null);
  const liveSessionRef = useRef<LiveNewsSession | null>(null);

  // Transcripts
  const currentInputRef = useRef<string>('');
  const currentOutputRef = useRef<string>('');

  useEffect(() => {
    // Initialize Live Session Wrapper
    liveSessionRef.current = new LiveNewsSession();

    return () => {
      stopSession();
    };
  }, []);

  // Scroll to bottom
  const chatEndRef = useRef<HTMLDivElement>(null);
  useEffect(() => {
    chatEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [chatHistory, currentInputRef.current, currentOutputRef.current]);

  const toggleInterest = (interest: Interest) => {
    if (appState !== AppState.DISCONNECTED) return; // Lock during session
    setSelectedInterests((prev) =>
      prev.includes(interest)
        ? prev.filter((i) => i !== interest)
        : [...prev, interest]
    );
  };

  const startSession = async () => {
    setErrorMsg(null);
    setAppState(AppState.CONNECTING);
    setChatHistory([]);
    nextStartTimeRef.current = 0;
    currentInputRef.current = '';
    currentOutputRef.current = '';

    try {
      // 1. Setup Audio Output
      audioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({
        sampleRate: 24000,
      });

      // 2. Setup Audio Input
      inputContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({
        sampleRate: 16000,
      });
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      inputStreamRef.current = stream;

      // 3. Connect to Gemini Live
      await liveSessionRef.current?.connect(
        selectedInterests,
        // onOpen
        () => {
          setAppState(AppState.CONNECTED);
          setupAudioInput(stream);
        },
        // onMessage
        async (message) => {
          // Handle Audio Output
          const base64Audio = message.serverContent?.modelTurn?.parts?.[0]?.inlineData?.data;
          if (base64Audio && audioContextRef.current) {
            playAudioChunk(base64Audio);
          }

          // Handle Transcripts
          if (message.serverContent?.outputTranscription) {
            currentOutputRef.current += message.serverContent.outputTranscription.text;
            updateChatHistory(false);
          }
          if (message.serverContent?.inputTranscription) {
            currentInputRef.current += message.serverContent.inputTranscription.text;
            updateChatHistory(false);
          }

          // Handle Turn Completion
          if (message.serverContent?.turnComplete) {
            updateChatHistory(true);
          }

          // Handle Interruption
          if (message.serverContent?.interrupted) {
            handleInterruption();
          }
        },
        // onClose
        () => {
          stopSession();
        },
        // onError
        (err) => {
          console.error("Live API Error:", err);
          setErrorMsg("Connection lost. Please try again.");
          stopSession();
        }
      );

    } catch (err) {
      console.error("Setup Error:", err);
      setErrorMsg("Could not access microphone or connect.");
      setAppState(AppState.DISCONNECTED);
    }
  };

  const setupAudioInput = (stream: MediaStream) => {
    if (!inputContextRef.current || !liveSessionRef.current) return;

    const source = inputContextRef.current.createMediaStreamSource(stream);
    const processor = inputContextRef.current.createScriptProcessor(4096, 1, 1);

    processor.onaudioprocess = (e) => {
      const inputData = e.inputBuffer.getChannelData(0);

      // Calculate volume for visualizer
      let sum = 0;
      for (let i = 0; i < inputData.length; i++) sum += inputData[i] * inputData[i];
      const rms = Math.sqrt(sum / inputData.length);
      setVolume(Math.min(rms * 5, 1)); // Scale up a bit

      const base64PCM = float32ToBase64PCM(inputData);
      liveSessionRef.current?.sendAudioChunk(base64PCM);
    };

    source.connect(processor);
    processor.connect(inputContextRef.current.destination);
    processorRef.current = processor;
  };

  const playAudioChunk = async (base64Audio: string) => {
    if (!audioContextRef.current) return;

    try {
      // Ensure context is running
      if (audioContextRef.current.state === 'suspended') {
        await audioContextRef.current.resume();
      }

      const bytes = atob(base64Audio);
      const array = new Uint8Array(bytes.length);
      for(let i=0; i<bytes.length; i++) array[i] = bytes.charCodeAt(i);

      const audioBuffer = await decodeAudioData(array, audioContextRef.current);

      // Schedule playback
      const currentTime = audioContextRef.current.currentTime;
      if (nextStartTimeRef.current < currentTime) {
        nextStartTimeRef.current = currentTime;
      }

      const source = audioContextRef.current.createBufferSource();
      source.buffer = audioBuffer;
      source.connect(audioContextRef.current.destination);
      source.start(nextStartTimeRef.current);

      audioSourcesRef.current.add(source);
      source.onended = () => audioSourcesRef.current.delete(source);

      nextStartTimeRef.current += audioBuffer.duration;

      // Visualizer volume boost when bot speaks (simulated as we don't have analyzer on output)
      setVolume(0.5); 

    } catch (e) {
      console.error("Audio Decode Error", e);
    }
  };

  const handleInterruption = () => {
    console.log("Bot interrupted!");
    audioSourcesRef.current.forEach(source => {
      try { source.stop(); } catch(e) {}
    });
    audioSourcesRef.current.clear();
    nextStartTimeRef.current = 0;
    currentOutputRef.current = ''; // Clear pending output transcript
  };

  const updateChatHistory = (isComplete: boolean) => {
    setChatHistory(prev => {
      const history = [...prev];

      // Update or add user message
      if (currentInputRef.current.trim()) {
        const lastMsg = history[history.length - 1];
        if (lastMsg && lastMsg.role === 'user' && !lastMsg.isFinal) {
          lastMsg.text = currentInputRef.current;
          if (isComplete) {
              lastMsg.isFinal = true;
              currentInputRef.current = ''; // Reset buffer
          }
        } else if (!isComplete || isComplete) {
          // Only add if not already there or it's a new turn
           if (!lastMsg || lastMsg.role !== 'user' || lastMsg.isFinal) {
             history.push({
               role: 'user',
               text: currentInputRef.current,
               isFinal: isComplete,
               timestamp: Date.now()
             });
             if (isComplete) currentInputRef.current = '';
           }
        }
      }

      // Update or add bot message
      if (currentOutputRef.current.trim()) {
         const lastMsg = history[history.length - 1];
         if (lastMsg && lastMsg.role === 'assistant' && !lastMsg.isFinal) {
            lastMsg.text = currentOutputRef.current;
            if (isComplete) {
                lastMsg.isFinal = true;
                currentOutputRef.current = '';
            }
         } else {
             if (!lastMsg || lastMsg.role !== 'assistant' || lastMsg.isFinal) {
                 history.push({
                     role: 'assistant',
                     text: currentOutputRef.current,
                     isFinal: isComplete,
                     timestamp: Date.now()
                 });
                 if (isComplete) currentOutputRef.current = '';
             }
         }
      }

      return history;
    });
  };

  const stopSession = () => {
    // 1. Close Live API
    liveSessionRef.current?.close();

    // 2. Stop Tracks
    inputStreamRef.current?.getTracks().forEach(t => t.stop());
    inputStreamRef.current = null;

    // 3. Disconnect Audio Nodes
    if (processorRef.current) {
      processorRef.current.disconnect();
      processorRef.current.onaudioprocess = null;
      processorRef.current = null;
    }

    // 4. Close Contexts
    inputContextRef.current?.close();
    audioContextRef.current?.close();

    setAppState(AppState.DISCONNECTED);
    setVolume(0);
  };

  return (
    <div className="min-h-screen bg-slate-900 text-slate-100 flex flex-col items-center relative overflow-hidden font-sans">

      {/* Background Ambience */}
      <div className="absolute top-0 left-0 w-full h-full overflow-hidden pointer-events-none z-0">
        <div className={`absolute -top-[20%] -right-[20%] w-[600px] h-[600px] bg-indigo-900/20 rounded-full blur-[100px] transition-opacity duration-1000 ${appState === AppState.CONNECTED ? 'opacity-100' : 'opacity-50'}`} />
        <div className={`absolute top-[40%] -left-[20%] w-[500px] h-[500px] bg-rose-900/20 rounded-full blur-[100px] transition-opacity duration-1000 ${appState === AppState.CONNECTED ? 'opacity-100' : 'opacity-50'}`} />
      </div>

      <div className="relative z-10 w-full max-w-2xl px-4 py-6 flex flex-col h-screen">

        {/* Header */}
        <header className="flex items-center justify-between mb-6">
          <div className="flex items-center space-x-3">
             <div className="w-10 h-10 bg-gradient-to-br from-indigo-500 to-rose-500 rounded-xl flex items-center justify-center shadow-lg shadow-indigo-500/20">
               <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6 text-white" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                 <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 20H5a2 2 0 01-2-2V6a2 2 0 012-2h10a2 2 0 012 2v1m2 13a2 2 0 01-2-2V7m2 13a2 2 0 002-2V9a2 2 0 00-2-2h-2m-4-3H9M7 16h6M7 8h6v4H7V8z" />
               </svg>
            </div>
            <div>
              <h1 className="text-xl font-bold tracking-tight">Vani Live</h1>
              <p className="text-xs text-slate-400">Gemini Native Audio</p>
            </div>
          </div>

          <div className="flex items-center space-x-2">
            <span className={`w-2 h-2 rounded-full transition-colors duration-300 ${appState === AppState.CONNECTED ? 'bg-red-500 animate-pulse' : 'bg-slate-600'}`} />
            <span className="text-xs font-medium text-slate-400 uppercase tracking-wider">
                {appState === AppState.CONNECTED ? 'LIVE' : appState === AppState.CONNECTING ? 'CONNECTING' : 'OFF AIR'}
            </span>
          </div>
        </header>

        {/* Categories Selection */}
        <div className="mb-6 transition-all duration-300 ease-in-out">
          <p className="text-xs font-semibold text-slate-500 mb-3 uppercase tracking-wider">
            {appState === AppState.CONNECTED ? 'Active Interests' : 'Select Interests'}
          </p>
          <div className={`flex flex-wrap gap-2 ${appState === AppState.CONNECTED ? 'opacity-70 pointer-events-none' : 'opacity-100'}`}>
            {INTERESTS_LIST.map((interest) => (
              <button
                key={interest}
                onClick={() => toggleInterest(interest)}
                className={`px-3 py-1.5 rounded-full text-xs font-medium transition-all duration-200 border ${
                  selectedInterests.includes(interest)
                    ? 'bg-indigo-600 border-indigo-500 text-white shadow-lg shadow-indigo-900/50'
                    : 'bg-slate-800/50 border-slate-700 text-slate-400 hover:bg-slate-800 hover:text-slate-200'
                }`}
              >
                {interest}
              </button>
            ))}
          </div>
        </div>

        {/* Transcript Area */}
        <div className="flex-1 overflow-y-auto scrollbar-hide -mx-4 px-4 pb-4 space-y-4">
            {chatHistory.length === 0 && appState === AppState.DISCONNECTED && (
                <div className="h-full flex flex-col items-center justify-center text-center opacity-50 space-y-4">
                     <div className="w-20 h-20 bg-slate-800 rounded-full flex items-center justify-center">
                        <svg xmlns="http://www.w3.org/2000/svg" className="h-10 w-10 text-slate-600" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1.5} d="M19 11a7 7 0 01-7 7m0 0a7 7 0 01-7-7m7 7v4m0 0H8m4 0h4m-4-8a3 3 0 01-3-3V5a3 3 0 116 0v6a3 3 0 01-3 3z" />
                        </svg>
                     </div>
                    <div>
                        <p className="text-lg font-medium text-slate-300">Ready to Go Live?</p>
                        <p className="text-sm text-slate-500 mt-1">Select your interests and tap "Start" to begin your personalized news broadcast.</p>
                    </div>
