import { GoogleGenAI, Modality, LiveServerMessage } from "@google/genai";
import { Interest } from "../types";

export class LiveNewsSession {
  private session: any = null;
  private currentInterestString: string = "";

  constructor() {}

  async connect(
    interests: Interest[],
    onOpen: () => void,
    onMessage: (message: LiveServerMessage) => void,
    onClose: (event: CloseEvent) => void,
    onError: (error: ErrorEvent) => void
  ) {
    // Initialize AI client here to ensure API_KEY is available at runtime
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

    this.currentInterestString = interests.length > 0 ? interests.join(", ") : "Top India Headlines";
    const today = new Date().toLocaleDateString('en-IN', { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' });

    const systemInstruction = `You are Vani, a senior investigative journalist and news anchor for India.
    Current Date: ${today}.
    User Interests: [${this.currentInterestString}].

    MANDATES FOR NEWS DELIVERY:
    1. **NEUTRALITY & REALISM**: You must report news objectively. Do NOT filter out negative news. If there is a stock market crash, political scandal, or crime, report it factually. Do not force a positive spin.
    2. **HIGH DETAIL**: Vague summaries are forbidden. You must include:
       - **Full Names** of people involved (Ministers, CEOs, Cricketers, Actors).
       - **Specific Entity Names** (e.g., instead of "a tech company", say "Infosys" or "OpenAI"; instead of "the government", say "The Finance Ministry").
       - **Exact Figures**: Quote amounts (₹ Crores), percentages, scores, or dates exactly.
    3. **INITIATIVE**: You MUST speak first. Do not wait for the user to say hello. As soon as the connection opens, say "Namaste" and launch into the top story.
    4. **Language**: Hinglish (Professional news delivery, but conversational).

    FORMAT:
    - Start with a crisp, hard-hitting headline.
    - Follow with a detailed report covering Who, What, Where, When, and Why.
    - Move to the next story without asking "Do you want more?". 
    - If the user interrupts, stop immediately.

    RESTRICTIONS:
    - Never be vague.
    - Never say "Some people said..." -> Say "Opposition leader X said...".
    `;

    this.session = await ai.live.connect({
      model: 'gemini-2.5-flash-native-audio-preview-12-2025',
      callbacks: {
        onopen: onOpen,
        onmessage: onMessage,
        onclose: onClose,
        onerror: onError,
      },
      config: {
        responseModalities: [Modality.AUDIO],
        systemInstruction: systemInstruction,
        speechConfig: {
          voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Kore' } }
        },
        // Tools removed to prevent Network Error in Live API
        inputAudioTranscription: {},
        outputAudioTranscription: {}
      }
    });

    return this.session;
  }

  async sendAudioChunk(base64PCM: string) {
    if (this.session) {
      try {
        this.session.sendRealtimeInput({
          media: {
            mimeType: 'audio/pcm;rate=16000',
            data: base64PCM
          }
        });
      } catch (e) {
        console.error("Error sending audio chunk", e);
      }
    }
  }

  async close() {
    if (this.session) {
      try {
        (this.session as any).close(); 
      } catch (e) {
        console.warn("Error closing session", e);
      }
      this.session = null;
    }
  }
}

import React, { useState, useRef, useEffect } from 'react';
import { Interest, AppState, ChatMessage, NewsSource } from './types';
import { LiveNewsSession } from './services/geminiService';
import { decodeAudioData, float32ToBase64PCM } from './services/audioUtils';
import Visualizer from './components/Visualizer';
import NewsCard from './components/NewsCard';

const INTERESTS_LIST = Object.values(Interest);

const App: React.FC = () => {
  // UI State
  const [selectedInterests, setSelectedInterests] = useState<Interest[]>([]);
  const [appState, setAppState] = useState<AppState>(AppState.DISCONNECTED);
  const [chatHistory, setChatHistory] = useState<ChatMessage[]>([]);
  const [errorMsg, setErrorMsg] = useState<string | null>(null);
  const [volume, setVolume] = useState<number>(0); // For visualizer

  // Audio Context Refs
  const audioContextRef = useRef<AudioContext | null>(null);
  const inputContextRef = useRef<AudioContext | null>(null);
  const nextStartTimeRef = useRef<number>(0);
  const audioSourcesRef = useRef<Set<AudioBufferSourceNode>>(new Set());
  const processorRef = useRef<ScriptProcessorNode | null>(null);
  const inputStreamRef = useRef<MediaStream | null>(null);
  const liveSessionRef = useRef<LiveNewsSession | null>(null);

  useEffect(() => {
    // Initialize Live Session Wrapper
    liveSessionRef.current = new LiveNewsSession();

    return () => {
      stopSession();
    };
  }, []);

  // Scroll to bottom
  const chatEndRef = useRef<HTMLDivElement>(null);
  useEffect(() => {
    chatEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [chatHistory]);

  const toggleInterest = (interest: Interest) => {
    if (appState !== AppState.DISCONNECTED) return; // Lock during session
    setSelectedInterests((prev) =>
      prev.includes(interest)
        ? prev.filter((i) => i !== interest)
        : [...prev, interest]
    );
  };

  const appendToChatHistory = (role: 'user' | 'assistant', text: string, sources?: NewsSource[]) => {
      setChatHistory(prev => {
          const history = [...prev];
          const lastMsg = history[history.length - 1];

          // If the last message is from the same role, append to it to create a continuous bubble
          if (lastMsg && lastMsg.role === role) {
              lastMsg.text += text;
              // Merge sources if new ones arrive
              if (sources && sources.length > 0) {
                  const existingUris = new Set(lastMsg.sources?.map(s => s.uri) || []);
                  const newSources = sources.filter(s => !existingUris.has(s.uri));
                  lastMsg.sources = [...(lastMsg.sources || []), ...newSources];
              }
              return [...history]; 
          } 

          // Otherwise create a new bubble
          return [...history, {
              role,
              text,
              isFinal: false,
              timestamp: Date.now(),
              sources: sources || []
          }];
      });
  };

  const startSession = async () => {
    setErrorMsg(null);
    setAppState(AppState.CONNECTING);
    setChatHistory([]);
    nextStartTimeRef.current = 0;

    try {
      // 1. Setup Audio Output
      audioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({
        sampleRate: 24000,
      });

      // 2. Setup Audio Input
      inputContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({
        sampleRate: 16000,
      });
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      inputStreamRef.current = stream;

      // 3. Connect to Gemini Live
      await liveSessionRef.current?.connect(
        selectedInterests,
        // onOpen
        () => {
          setAppState(AppState.CONNECTED);
          setupAudioInput(stream);
        },
        // onMessage
        async (message) => {
          // Handle Audio Output
          const base64Audio = message.serverContent?.modelTurn?.parts?.[0]?.inlineData?.data;
          if (base64Audio && audioContextRef.current) {
            playAudioChunk(base64Audio);
          }

          // Handle Grounding (Search Sources)
          let currentSources: NewsSource[] = [];
          const parts = message.serverContent?.modelTurn?.parts;
          if (parts) {
              parts.forEach((part: any) => {
                  if (part.groundingMetadata?.groundingChunks) {
                      part.groundingMetadata.groundingChunks.forEach((chunk: any) => {
                          if (chunk.web?.uri && chunk.web?.title) {
                              currentSources.push({
                                  title: chunk.web.title,
                                  uri: chunk.web.uri
                              });
                          }
                      });
                  }
              });
          }

          // Handle Transcripts
          if (message.serverContent?.outputTranscription) {
             const text = message.serverContent.outputTranscription.text;
             if (text) appendToChatHistory('assistant', text, currentSources);
          } else if (currentSources.length > 0) {
             // If we have sources but no text chunk in this specific message, attach to last message
             appendToChatHistory('assistant', '', currentSources);
          }

          if (message.serverContent?.inputTranscription) {
             const text = message.serverContent.inputTranscription.text;
             if (text) appendToChatHistory('user', text);
          }

          // Handle Interruption
          if (message.serverContent?.interrupted) {
            handleInterruption();
          }
        },
        // onClose
        () => {
          stopSession();
        },
        // onError
        (err) => {
          console.error("Live API Error:", err);
          setErrorMsg("Connection error. Please check your network or API key.");
          stopSession();
        }
      );

      // Removed manual sendText trigger to rely on System Instruction and avoid session errors

    } catch (err) {
      console.error("Setup Error:", err);
      setErrorMsg("Could not access microphone or connect.");
      setAppState(AppState.DISCONNECTED);
    }
  };

  const setupAudioInput = (stream: MediaStream) => {
    if (!inputContextRef.current || !liveSessionRef.current) return;

    const source = inputContextRef.current.createMediaStreamSource(stream);
    const processor = inputContextRef.current.createScriptProcessor(4096, 1, 1);

    processor.onaudioprocess = (e) => {
      const inputData = e.inputBuffer.getChannelData(0);

      // Calculate volume for visualizer
      let sum = 0;
      for (let i = 0; i < inputData.length; i++) sum += inputData[i] * inputData[i];
      const rms = Math.sqrt(sum / inputData.length);
      setVolume(Math.min(rms * 5, 1)); // Scale up a bit

      const base64PCM = float32ToBase64PCM(inputData);
      liveSessionRef.current?.sendAudioChunk(base64PCM);
    };

    source.connect(processor);
    processor.connect(inputContextRef.current.destination);
    processorRef.current = processor;
  };

  const playAudioChunk = async (base64Audio: string) => {
    if (!audioContextRef.current) return;

    try {
      // Ensure context is running
      if (audioContextRef.current.state === 'suspended') {
        await audioContextRef.current.resume();
      }

      const bytes = atob(base64Audio);
      const array = new Uint8Array(bytes.length);
      for(let i=0; i<bytes.length; i++) array[i] = bytes.charCodeAt(i);

      const audioBuffer = await decodeAudioData(array, audioContextRef.current);

      // Schedule playback
      const currentTime = audioContextRef.current.currentTime;
      if (nextStartTimeRef.current < currentTime) {
        nextStartTimeRef.current = currentTime;
      }

      const source = audioContextRef.current.createBufferSource();
      source.buffer = audioBuffer;
      source.connect(audioContextRef.current.destination);
      source.start(nextStartTimeRef.current);

      audioSourcesRef.current.add(source);
      source.onended = () => audioSourcesRef.current.delete(source);

      nextStartTimeRef.current += audioBuffer.duration;

      // Visualizer volume boost when bot speaks
      setVolume(0.5); 

    } catch (e) {
      console.error("Audio Decode Error", e);
    }
  };

  const handleInterruption = () => {
    console.log("Bot interrupted!");
    // Stop all currently playing audio
    audioSourcesRef.current.forEach(source => {
      try { source.stop(); } catch(e) {}
    });
    audioSourcesRef.current.clear();

    // Reset playback cursor to now, effectively clearing the queue
    if (audioContextRef.current) {
        nextStartTimeRef.current = audioContextRef.current.currentTime;
    }
  };

  const stopSession = () => {
    // 1. Close Live API
    liveSessionRef.current?.close();

    // 2. Stop Tracks
    if (inputStreamRef.current) {
        inputStreamRef.current.getTracks().forEach(t => t.stop());
        inputStreamRef.current = null;
    }

    // 3. Disconnect Audio Nodes
    if (processorRef.current) {
      try {
        processorRef.current.disconnect();
        processorRef.current.onaudioprocess = null;
      } catch (e) { /* ignore */ }
      processorRef.current = null;
    }

    // 4. Close Contexts safely
    if (inputContextRef.current && inputContextRef.current.state !== 'closed') {
        try { inputContextRef.current.close(); } catch(e) {}
    }
    inputContextRef.current = null;

    if (audioContextRef.current && audioContextRef.current.state !== 'closed') {
        try { audioContextRef.current.close(); } catch(e) {}
    }
    audioContextRef.current = null;

    setAppState(AppState.DISCONNECTED);
    setVolume(0);
  };

  return (
    <div className="min-h-screen bg-slate-900 text-slate-100 flex flex-col items-center relative overflow-hidden font-sans">

      {/* Background Ambience */}
      <div className="absolute top-0 left-0 w-full h-full overflow-hidden pointer-events-none z-0">
        <div className={`absolute -top-[20%] -right-[20%] w-[600px] h-[600px] bg-indigo-900/20 rounded-full blur-[100px] transition-opacity duration-1000 ${appState === AppState.CONNECTED ? 'opacity-100' : 'opacity-50'}`} />
        <div className={`absolute top-[40%] -left-[20%] w-[500px] h-[500px] bg-rose-900/20 rounded-full blur-[100px] transition-opacity duration-1000 ${appState === AppState.CONNECTED ? 'opacity-100' : 'opacity-50'}`} />
      </div>

      <div className="relative z-10 w-full max-w-2xl px-4 py-6 flex flex-col h-screen">

        {/* Header */}
        <header className="flex items-center justify-between mb-6">
          <div className="flex items-center space-x-3">
             <div className="w-10 h-10 bg-gradient-to-br from-indigo-500 to-rose-500 rounded-xl flex items-center justify-center shadow-lg shadow-indigo-500/20">
               <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6 text-white" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                 <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 20H5a2 2 0 01-2-2V6a2 2 0 012-2h10a2 2 0 012 2v1m2 13a2 2 0 01-2-2V7m2 13a2 2 0 002-2V9a2 2 0 00-2-2h-2m-4-3H9M7 16h6M7 8h6v4H7V8z" />
               </svg>
            </div>
            <div>
              <h1 className="text-xl font-bold tracking-tight">Vani Live</h1>
              <p className="text-xs text-slate-400">Gemini Native Audio</p>
            </div>
          </div>

          <div className="flex items-center space-x-2">
            <span className={`w-2 h-2 rounded-full transition-colors duration-300 ${appState === AppState.CONNECTED ? 'bg-red-500 animate-pulse' : 'bg-slate-600'}`} />
            <span className="text-xs font-medium text-slate-400 uppercase tracking-wider">
                {appState === AppState.CONNECTED ? 'LIVE' : appState === AppState.CONNECTING ? 'CONNECTING' : 'OFF AIR'}
            </span>
          </div>
        </header>

        {/* Categories Selection */}
        <div className="mb-6 transition-all duration-300 ease-in-out">
          <p className="text-xs font-semibold text-slate-500 mb-3 uppercase tracking-wider">
            {appState === AppState.CONNECTED ? 'Active Interests' : 'Select Interests'}
          </p>
          <div className={`flex flex-wrap gap-2 ${appState === AppState.CONNECTED ? 'opacity-70 pointer-events-none' : 'opacity-100'}`}>
            {INTERESTS_LIST.map((interest) => (
              <button
                key={interest}
                onClick={() => toggleInterest(interest)}
                className={`px-3 py-1.5 rounded-full text-xs font-medium transition-all duration-200 border ${
                  selectedInterests.includes(interest)
                    ? 'bg-indigo-600 border-indigo-500 text-white shadow-lg shadow-indigo-900/50'
                    : 'bg-slate-800/50 border-slate-700 text-slate-400 hover:bg-slate-800 hover:text-slate-200'
                }`}
              >
                {interest}
              </button>
            ))}
          </div>
        </div>

        {/* Transcript Area */}
        <div className="flex-1 overflow-y-auto scrollbar-hide -mx-4 px-4 pb-4 space-y-4">
            {chatHistory.length === 0 && appState === AppState.DISCONNECTED && (
                <div className="h-full flex flex-col items-center justify-center text-center opacity-50 space-y-4">
                     <div className="w-20 h-20 bg-slate-800 rounded-full flex items-center justify-center">
                        <svg xmlns="http://www.w3.org/2000/svg" className="h-10 w-10 text-slate-600" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1.5} d="M19 11a7 7 0 01-7 7m0 0a7 7 0 01-7-7m7 7v4m0 0H8m4 0h4m-4-8a3 3 0 01-3-3V5a3 3 0 116 0v6a3 3 0 01-3 3z" />
                        </svg>
                     </div>
                    <div>
                        <p className="text-lg font-medium text-slate-300">Ready to Go Live?</p>
                        <p className="text-sm text-slate-500 mt-1">Select your interests and tap "Start" to begin your personalized news broadcast.</p>
                    </div>
                </div>
            )}

            {chatHistory.map((msg, idx) => (
                <NewsCard key={idx} message={msg} />
            ))}
            <div ref={chatEndRef} />
        </div>

        {/* Error Notification */}
        {errorMsg && (
            <div className="mb-4 bg-red-500/10 border border-red-500/50 text-red-400 px-4 py-3 rounded-xl text-sm flex items-center gap-3">
                <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5 shrink-0" viewBox="0 0 20 20" fill="currentColor">
                    <path fillRule="evenodd" d="M10 18a8 8 0 100-16 8 8 0 000 16zM8.707 7.293a1 1 0 00-1.414 1.414L8.586 10l-1.293 1.293a1 1 0 101.414 1.414L10 11.414l1.293 1.293a1 1 0 001.414-1.414L11.414 10l1.293-1.293a1 1 0 00-1.414-1.414L10 8.586 8.707 7.293z" clipRule="evenodd" />
